const geminiJson = $input.first().json;
const trigger = $('TelegramTrigger').first().json;
const chatId = String(trigger.message?.chat?.id || trigger.callback_query?.message?.chat?.id || '');
const updateId = String(trigger.update_id || 'N/A');
const messageId = String(trigger.message?.message_id || trigger.callback_query?.message?.message_id || 'N/A');
const photos = trigger.message?.photo || [];
const fileIdOrigen = photos.length ? String(photos[photos.length - 1].file_id || 'N/A') : 'N/A';
const raw = geminiJson.text || geminiJson.content?.parts?.[0]?.text || geminiJson.content || JSON.stringify(geminiJson);

const toBool = (value) => {
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  const normalized = String(value || '').trim().toLowerCase();
  return ['true', '1', 'x', 'si', 'sí', 'yes'].includes(normalized);
};

const getText = (value, fallback = 'N/A') => {
  if (value === undefined || value === null) return fallback;
  const text = String(value).trim();
  if (!text) return fallback;
  const normalized = text.toLowerCase();
  return ['n/a', 'na', 'null', 'undefined'].includes(normalized) ? fallback : text;
};

const normalizeYear = (value) => {
  const text = getText(value);
  if (text === 'N/A') return text;
  return /^\d{2}$/.test(text) ? `20${text}` : text;
};

const normalizeFullDate = (value) => {
  const text = getText(value);
  if (text === 'N/A') return text;
  const match = text.match(/^(\d{2})\/(\d{2})\/(\d{2})$/);
  return match ? `${match[1]}/${match[2]}/20${match[3]}` : text;
};

const normalizeFailureCode = (value) => {
  const text = getText(value);
  if (text === 'N/A') return text;
  const compact = text.replace(/\s+/g, '');
  if (/^\d\.\d$/.test(compact)) return compact;
  if (/^\d{2}$/.test(compact)) return `${compact[0]}.${compact[1]}`;
  return compact;
};

const normalizeKey = (value) => String(value || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9]+/g, ' ')
  .trim();

const equipmentLabelMap = {
  c1: 'C1',
  c2: 'C2',
  c3: 'C3',
  c4: 'C4',
  c5: 'C5',
  c6: 'C6',
  'bba miel 1': 'BBA MIEL 1',
  'bba miel 2': 'BBA MIEL 2',
  'bomba miel 1': 'BBA MIEL 1',
  'bomba miel 2': 'BBA MIEL 2',
  mezclador: 'MEZCLADOR',
  gusanillo: 'GUSANILLO',
};

const canonicalizeEquipmentLabel = (value) => {
  const text = getText(value, '');
  if (!text) return '';
  const key = normalizeKey(text);
  return equipmentLabelMap[key] || text.toUpperCase();
};

const unique = (values) => [...new Set(values.filter(Boolean))];

let parsed = null;
try {
  const jsonMatch = raw.match(/\{[\s\S]*\}|\[[\s\S]*\]/);
  if (jsonMatch) parsed = JSON.parse(jsonMatch[0]);
} catch (error) {
  parsed = null;
}

let documento = {};
let items = [];
if (Array.isArray(parsed)) {
  items = parsed;
} else if (parsed && Array.isArray(parsed.items)) {
  documento = parsed.documento || {};
  items = parsed.items;
} else if (parsed && typeof parsed === 'object') {
  items = [parsed];
}

if (!items.length) {
  items = [{
    item_index: 1,
    fecha_dia: 'N/A',
    fecha_mes: 'N/A',
    fecha_anio: 'N/A',
    fecha_registro: 'N/A',
    hora_inicio: 'N/A',
    periodo_inicio: 'N/A',
    hora_fin: 'N/A',
    periodo_fin: 'N/A',
    tiempo_falla_min: 'N/A',
    equipos: {},
    equipos_afectados: [],
    tipo_falla: {
      categoria: 'N/A',
      codigo: 'N/A',
      mecanica: 'N/A',
      electrica: 'N/A',
      instrumentacion: 'N/A',
      otros: 'N/A',
    },
    observaciones: 'N/A',
    firma_hallazgo: 'N/A',
    _parse_error: true,
  }];
}

const fechaEmisionDocumento = normalizeFullDate(documento.fecha_emision);
const ubicacionDocumento = getText(documento.ubicacion);
const plantaDocumento = getText(documento.planta);

return items.map((item, index) => {
  const equipos = item.equipos || {};
  const tipoFalla = item.tipo_falla || {};

  const equiposDesdeLista = Array.isArray(item.equipos_afectados)
    ? item.equipos_afectados.map(canonicalizeEquipmentLabel).filter(Boolean)
    : [];

  const equiposDesdeChecks = [
    ['C1', equipos.c1],
    ['C2', equipos.c2],
    ['C3', equipos.c3],
    ['C4', equipos.c4],
    ['C5', equipos.c5],
    ['C6', equipos.c6],
    ['BBA MIEL 1', equipos.bba_miel_1],
    ['BBA MIEL 2', equipos.bba_miel_2],
    ['MEZCLADOR', equipos.mezclador],
    ['GUSANILLO', equipos.gusanillo],
  ].filter(([, value]) => toBool(value)).map(([label]) => label);

  const equiposDerivados = unique([...equiposDesdeLista, ...equiposDesdeChecks]);

  const tipoFallaMecanica = normalizeFailureCode(tipoFalla.mecanica);
  const tipoFallaElectrica = normalizeFailureCode(tipoFalla.electrica);
  const tipoFallaInstrumentacion = normalizeFailureCode(tipoFalla.instrumentacion);
  const tipoFallaOtros = normalizeFailureCode(tipoFalla.otros);
  const tipoFallaCodigo = [
    normalizeFailureCode(tipoFalla.codigo),
    tipoFallaMecanica,
    tipoFallaElectrica,
    tipoFallaInstrumentacion,
    tipoFallaOtros,
  ].find((value) => value !== 'N/A') || 'N/A';

  const categoriaInferida = tipoFallaMecanica !== 'N/A'
    ? 'Mecanica'
    : tipoFallaElectrica !== 'N/A'
      ? 'Electrica'
      : tipoFallaInstrumentacion !== 'N/A'
        ? 'Instrumentacion'
        : tipoFallaOtros !== 'N/A'
          ? 'Otros'
          : 'N/A';

  return {
    json: {
      chatId,
      Timestamp: new Date().toISOString(),
      Chat_ID: chatId,
      Update_ID: updateId,
      Message_ID: messageId,
      File_ID_Origen: fileIdOrigen,
      Fecha_Emision_Documento: fechaEmisionDocumento,
      Ubicacion: ubicacionDocumento,
      Planta: plantaDocumento,
      Item_Index: item.item_index ?? index + 1,
      Fecha_Dia: getText(item.fecha_dia),
      Fecha_Mes: getText(item.fecha_mes),
      Fecha_Anio: normalizeYear(item.fecha_anio),
      Fecha_Registro: normalizeFullDate(item.fecha_registro),
      Hora_Inicio: getText(item.hora_inicio),
      Periodo_Inicio: getText(item.periodo_inicio),
      Hora_Fin: getText(item.hora_fin),
      Periodo_Fin: getText(item.periodo_fin),
      Tiempo_Falla_Min: getText(item.tiempo_falla_min),
      Equipo_C1: toBool(equipos.c1),
      Equipo_C2: toBool(equipos.c2),
      Equipo_C3: toBool(equipos.c3),
      Equipo_C4: toBool(equipos.c4),
      Equipo_C5: toBool(equipos.c5),
      Equipo_C6: toBool(equipos.c6),
      Equipo_BBA_MIEL_1: toBool(equipos.bba_miel_1),
      Equipo_BBA_MIEL_2: toBool(equipos.bba_miel_2),
      Equipo_MEZCLADOR: toBool(equipos.mezclador),
      Equipo_GUSANILLO: toBool(equipos.gusanillo),
      Equipos_Afectados: equiposDerivados.length ? equiposDerivados.join(', ') : 'N/A',
      Tipo_Falla_Categoria: getText(tipoFalla.categoria, categoriaInferida),
      Tipo_Falla_Codigo: tipoFallaCodigo,
      Tipo_Falla_Mecanica: tipoFallaMecanica,
      Tipo_Falla_Electrica: tipoFallaElectrica,
      Tipo_Falla_Instrumentacion: tipoFallaInstrumentacion,
      Tipo_Falla_Otros: tipoFallaOtros,
      Observaciones: getText(item.observaciones),
      Firma_Hallazgo: getText(item.firma_hallazgo),
      Estado_OCR: item._parse_error ? 'Requiere Revision' : 'Procesado',
      Respuesta_Cruda: raw,
    },
  };
});

const rows = $('FormatearDatos').all().map((item) => item.json);
const first = rows[0] || {};

const isMissing = (value) => {
  const text = String(value ?? '').trim();
  return text === '' || /^n\/?a$/i.test(text) || /^no detectad/i.test(text);
};

const formatField = (value, fallback) => isMissing(value) ? fallback : String(value).trim();
const parseDate = (value) => {
  const text = formatField(value, '');
  const match = text.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if (!match) return null;
  return {
    label: text,
    time: Date.UTC(Number(match[3]), Number(match[2]) - 1, Number(match[1])),
  };
};

const validDates = rows.map((row) => parseDate(row.Fecha_Registro)).filter(Boolean).sort((a, b) => a.time - b.time);
const rangoFechas = !validDates.length
  ? 'No detectado'
  : validDates[0].label === validDates[validDates.length - 1].label
    ? validDates[0].label
    : `${validDates[0].label} a ${validDates[validDates.length - 1].label}`;

const filasRevision = rows
  .filter((row) => row.Estado_OCR === 'Requiere Revision')
  .map((row, index) => row.Item_Index ?? index + 1);

const resumen = rows.slice(0, 3).map((row) => {
  const fecha = formatField(row.Fecha_Registro, 'Fecha no detectada');
  const equipo = formatField(row.Equipos_Afectados, 'Equipo no detectado');
  const categoria = formatField(row.Tipo_Falla_Categoria, '');
  const codigo = formatField(row.Tipo_Falla_Codigo, '');
  const falla = [categoria, codigo].filter(Boolean).join(' ');
  return `- ${fecha} | ${equipo}${falla ? ` | ${falla}` : ''}`;
}).join('\n');

return [{
  json: {
    chatId: first.chatId || first.Chat_ID || '',
    total_items: rows.length,
    items_revision: filasRevision.length,
    filas_revision: filasRevision.length ? filasRevision.join(', ') : 'Ninguna',
    rango_fechas: rangoFechas,
    estado_ocr: filasRevision.length ? 'requiere validacion' : 'estable',
    resumen: resumen || '- Sin items',
  },
}];

