const first = $input.first();
const event = first.json;
const workflowStaticData = $getWorkflowStaticData('global');
workflowStaticData.chatModes = workflowStaticData.chatModes || {};
workflowStaticData.chatHistories = workflowStaticData.chatHistories || {};

const chatId = String(event.message?.chat?.id || event.callback_query?.message?.chat?.id || '');
const callbackData = String(event.callback_query?.data || '');
const text = String(event.message?.text || '').trim();
const hasPhoto = Array.isArray(event.message?.photo) && event.message.photo.length > 0;
const normalize = (value) => String(value || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/\s+/g, ' ')
  .trim();
const normalizedText = normalize(text);
const currentMode = workflowStaticData.chatModes[chatId] || 'menu';
const exitTexts = new Set(['/menu', 'menu', 'volver al menu', 'volver al menú', 'volver', 'salir', 'cancelar']);

let route = 'menu';
let promptType = '';

if (callbackData === 'upload') {
  workflowStaticData.chatModes[chatId] = 'ocr_wait_photo';
  delete workflowStaticData.chatHistories[chatId];
  route = 'ocr_prompt';
  promptType = 'ocr_start';
} else if (callbackData === 'chat') {
  workflowStaticData.chatModes[chatId] = 'chat_query';
  workflowStaticData.chatHistories[chatId] = [];
  route = 'chat_prompt';
  promptType = 'chat_start';
} else if (callbackData === 'back_menu' || exitTexts.has(normalizedText)) {
  delete workflowStaticData.chatModes[chatId];
  delete workflowStaticData.chatHistories[chatId];
  route = 'menu';
} else if (hasPhoto) {
  if (currentMode === 'chat_query') {
    route = 'chat_query';
  } else {
    delete workflowStaticData.chatModes[chatId];
    route = 'ocr_process';
  }
} else if (text) {
  if (currentMode === 'chat_query') {
    route = 'chat_query';
  } else if (currentMode === 'ocr_wait_photo') {
    route = 'ocr_prompt';
    promptType = 'ocr_waiting_photo';
  } else {
    route = 'menu';
  }
}

return [{
  json: {
    ...event,
    chatId,
    route,
    promptType,
    queryText: text,
    currentMode,
    callbackData,
  },
  binary: first.binary,
}];

const source = $('ProcesarConsulta').first().json;
const payload = $input.first().json;
const workflowStaticData = $getWorkflowStaticData('global');
workflowStaticData.chatHistories = workflowStaticData.chatHistories || {};

const modelParts = Array.isArray(payload?.content?.parts) ? payload.content.parts : [];
const candidateParts = Array.isArray(payload?.candidates?.[0]?.content?.parts) ? payload.candidates[0].content.parts : [];
const parts = modelParts.length ? modelParts : candidateParts;
const partsText = parts.map((part) => typeof part?.text === 'string' ? part.text : '').filter(Boolean).join('\n').trim();
const directText = typeof payload?.text === 'string' ? payload.text.trim() : '';
const responseText = (partsText || directText || 'Consulta de registros\n\nNo encontrado en los registros.').replace(/\r/g, '').trim();

const chatId = String(source.chatId || '');
const userQuery = String(source.userQuery || '').trim();
const history = Array.isArray(workflowStaticData.chatHistories[chatId]) ? workflowStaticData.chatHistories[chatId] : [];
if (userQuery) history.push({ role: 'user', text: userQuery });
history.push({ role: 'assistant', text: responseText });
workflowStaticData.chatHistories[chatId] = history.slice(-8);

return [{ json: { chatId, responseText } }];
